const settings = $('Load Action Settings').first()?.json ?? {};
const request = $('Case Tracking Actions Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? request.query ?? request;
const headers = request.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = authority + ':' + forwardedPort;
  }
  return proto + '://' + authority;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const action = clean(body.action);
const caseId = /^[0-9a-fA-F-]{36}$/.test(clean(body.case_id)) ? clean(body.case_id) : '';
const allowedPriorities = new Set(['Low', 'Medium', 'High', 'Urgent']);
const priority = allowedPriorities.has(clean(body.priority)) ? clean(body.priority) : 'Medium';
const allowedStatuses = new Set(['New', 'In Progress', 'Waiting', 'Completed']);
const status = allowedStatuses.has(clean(body.status)) ? clean(body.status) : 'New';
const returnUrl = clean(body.return_url) || (n8nBaseUrl + '/webhook/case-tracking?view=dashboard');
let errorMessage = '';
if (action === 'create_case') {
  if (!clean(body.title)) errorMessage = 'Title is required.';
  else if (!clean(body.contact_name)) errorMessage = 'Contact name is required.';
} else if (action === 'update_case') {
  if (!caseId) errorMessage = 'A valid case id is required.';
  else if (!clean(body.title)) errorMessage = 'Title is required.';
  else if (!clean(body.contact_name)) errorMessage = 'Contact name is required.';
} else if (action === 'add_note') {
  if (!caseId) errorMessage = 'A valid case id is required.';
  else if (!clean(body.note_text)) errorMessage = 'Note text is required.';
} else if (action === 'save_signature') {
  if (!clean(body.template_key)) errorMessage = 'template_key is required.';
  else if (!clean(body.template_name)) errorMessage = 'Template name is required.';
} else if (action === 'save_settings') {
  if (!clean(body.email_test_recipient)) errorMessage = 'Test recipient is required.';
} else {
  errorMessage = 'Unsupported action.';
}
return [{ json: {
  action, case_id: caseId, return_url: returnUrl, n8n_base_url: n8nBaseUrl,
  title: clean(body.title), contact_name: clean(body.contact_name), contact_email: clean(body.contact_email), contact_phone: clean(body.contact_phone),
  source: clean(body.source) || 'manual', priority, status, notes: clean(body.notes), opening_note: clean(body.opening_note),
  note_text: clean(body.note_text), template_key: clean(body.template_key), template_name: clean(body.template_name), text_template: body.text_template ?? '', html_template: body.html_template ?? '',
  email_delivery_mode: clean(body.email_delivery_mode) === 'production' ? 'production' : 'test',
  email_test_recipient: clean(body.email_test_recipient), email_sender_name: clean(body.email_sender_name), email_reply_to: clean(body.email_reply_to), email_signature_template_key: clean(body.email_signature_template_key), n8n_base_url_setting: clean(body.n8n_base_url),
  error_message: errorMessage
} }];

const input = $('Resolve Action Request').first()?.json ?? {};
const message = input.error_message || 'Unable to complete the requested action.';
const redirectTo = (input.return_url || '#') + ((input.return_url || '').includes('?') ? '&' : '?') + 'error=' + encodeURIComponent(message);
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=' + escapeHtml(redirectTo) + '"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Action failed</title></head><body><p>' + escapeHtml(message) + '</p><p><a href="' + escapeHtml(redirectTo) + '">Continue</a></p></body></html>';
return [{ json: { html } }];

const input = $input.first().json ?? {};
const sqlLiteral = (value) => value === null || value === undefined ? 'NULL' : "'" + String(value).replace(/'/g, "''") + "'";
let sql = '';
let successTitle = 'Saved';
let successMessage = 'Changes saved.';
if (input.action === 'create_case') {
  sql = [
    'WITH inserted_case AS (',
    '  INSERT INTO public.cases (title, contact_name, contact_email, contact_phone, source, status, priority, notes, created_by, updated_at)',
    '  VALUES (' + [sqlLiteral(input.title), sqlLiteral(input.contact_name), sqlLiteral(input.contact_email), sqlLiteral(input.contact_phone), sqlLiteral(input.source), sqlLiteral('New'), sqlLiteral(input.priority), sqlLiteral(input.opening_note), sqlLiteral('case-tracking'), 'now()'].join(', ') + ')',
    '  RETURNING id, title, contact_name',
    '), inserted_note AS (',
    '  INSERT INTO public.case_emails (case_id, direction, subject, body_text, created_by, created_at)',
    "  SELECT id, " + sqlLiteral('note') + ", " + sqlLiteral('Case created') + ", NULLIF(" + sqlLiteral(input.opening_note) + ", ''), " + sqlLiteral('case-tracking') + ", now()",
    '  FROM inserted_case',
    "  WHERE NULLIF(" + sqlLiteral(input.opening_note) + ", '') IS NOT NULL",
    '  RETURNING id',
    ')',
    'SELECT id::text AS case_id, title, contact_name FROM inserted_case'
  ].join('\n');
  successTitle = 'Case created';
  successMessage = 'The new case is ready.';
} else if (input.action === 'update_case') {
  sql = [
    'UPDATE public.cases',
    'SET',
    '  title = ' + sqlLiteral(input.title) + ',',
    '  contact_name = ' + sqlLiteral(input.contact_name) + ',',
    '  contact_email = ' + sqlLiteral(input.contact_email) + ',',
    '  contact_phone = ' + sqlLiteral(input.contact_phone) + ',',
    '  status = ' + sqlLiteral(input.status) + ',',
    '  priority = ' + sqlLiteral(input.priority) + ',',
    '  notes = ' + sqlLiteral(input.notes) + ',',
    '  updated_at = now(),',
    "  closed_at = CASE WHEN " + sqlLiteral(input.status) + " = 'Completed' THEN COALESCE(closed_at, now()) ELSE NULL END",
    'WHERE id = ' + sqlLiteral(input.case_id) + '::uuid',
    'RETURNING id::text AS case_id, title'
  ].join('\n');
  successTitle = 'Case updated';
  successMessage = 'Case details saved.';
} else if (input.action === 'add_note') {
  sql = [
    'WITH inserted_note AS (',
    '  INSERT INTO public.case_emails (case_id, direction, subject, body_text, created_by, created_at)',
    '  VALUES (' + [sqlLiteral(input.case_id) + '::uuid', sqlLiteral('note'), sqlLiteral('Internal note'), sqlLiteral(input.note_text), sqlLiteral('case-tracking'), 'now()'].join(', ') + ')',
    '  RETURNING case_id',
    '), updated_case AS (',
    '  UPDATE public.cases',
    '  SET updated_at = now()',
    '  WHERE id = (SELECT case_id FROM inserted_note)',
    '  RETURNING id',
    ')',
    'SELECT id::text AS case_id FROM updated_case'
  ].join('\n');
  successTitle = 'Note saved';
  successMessage = 'The case note was added.';
} else if (input.action === 'save_signature') {
  sql = [
    'UPDATE public.email_templates',
    'SET',
    '  template_name = ' + sqlLiteral(input.template_name) + ',',
    '  text_template = ' + sqlLiteral(input.text_template) + ',',
    '  html_template = ' + sqlLiteral(input.html_template) + ',',
    '  updated_at = now()',
    'WHERE template_key = ' + sqlLiteral(input.template_key),
    '  AND template_type = 2',
    'RETURNING template_key'
  ].join('\n');
  successTitle = 'Signature saved';
  successMessage = 'Signature template updated.';
} else if (input.action === 'save_settings') {
  const values = [
    ['email_delivery_mode', input.email_delivery_mode, 'Default case-tracking delivery mode'],
    ['email_test_recipient', input.email_test_recipient, 'Case-tracking test recipient'],
    ['email_sender_name', input.email_sender_name, 'Case-tracking sender name'],
    ['email_reply_to', input.email_reply_to, 'Case-tracking reply-to address'],
    ['email_signature_template_key', input.email_signature_template_key, 'Default signature template used by case tracking'],
    ['n8n_base_url', input.n8n_base_url_setting, 'Base URL used in generated case-tracking links']
  ];
  sql = [
    'WITH incoming(key, value, description) AS (',
    '  VALUES',
    values.map((item) => '    (' + [sqlLiteral(item[0]), sqlLiteral(item[1]), sqlLiteral(item[2])].join(', ') + ')').join(',\n'),
    '), upserted AS (',
    '  INSERT INTO public.global_settings (key, value, description, updated_at)',
    '  SELECT key, value, description, now() FROM incoming',
    '  ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, description = EXCLUDED.description, updated_at = now()',
    '  RETURNING key',
    ')',
    'SELECT count(*)::text AS updated_count FROM upserted'
  ].join('\n');
  successTitle = 'Settings saved';
  successMessage = 'Global settings updated.';
}
return [{ json: { ...input, sql, success_title: successTitle, success_message: successMessage } }];

const input = $('Build Action SQL').first()?.json ?? {};
const result = $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
let redirectTo = input.return_url || (input.n8n_base_url + '/webhook/case-tracking?view=dashboard');
if (input.action === 'create_case' && clean(result.case_id)) {
  redirectTo = input.n8n_base_url + '/webhook/case-tracking?view=case&id=' + encodeURIComponent(result.case_id);
} else if ((input.action === 'update_case' || input.action === 'add_note') && clean(result.case_id)) {
  redirectTo = input.n8n_base_url + '/webhook/case-tracking?view=case&id=' + encodeURIComponent(result.case_id);
} else if (input.action === 'save_signature' && clean(input.template_key)) {
  redirectTo = input.n8n_base_url + '/webhook/case-tracking?view=signatures&template_key=' + encodeURIComponent(input.template_key);
} else if (input.action === 'save_settings') {
  redirectTo = input.n8n_base_url + '/webhook/case-tracking?view=settings';
}
redirectTo += (redirectTo.includes('?') ? '&' : '?') + 'message=' + encodeURIComponent(input.success_message || 'Saved');
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = '<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=' + escapeHtml(redirectTo) + '"><meta name="viewport" content="width=device-width, initial-scale=1"><title>' + escapeHtml(input.success_title) + '</title></head><body><p>Saved. Redirecting…</p><p><a href="' + escapeHtml(redirectTo) + '">Continue</a></p></body></html>';
return [{ json: { html } }];
